import{_ as i,o as t,c as o,ag as a}from"./chunks/framework.NIzFHKo_.js";const h=JSON.parse('{"title":"QiAccess Start Portal","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/40_service_apps/120_applications/portal.md","filePath":"10_core/40_service_apps/120_applications/portal.md"}'),l={name:"10_core/40_service_apps/120_applications/portal.md"};function s(r,e,n,c,d,u){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="qiaccess-start-portal" tabindex="-1">QiAccess Start Portal <a class="header-anchor" href="#qiaccess-start-portal" aria-label="Permalink to &quot;QiAccess Start Portal&quot;">​</a></h1><p>QiAccess Start is Cody&#39;s cognitive front door.</p><p>It is not just a dashboard, launcher, or control panel. It is the active portal doctrine for this master blueprint.</p><h2 id="two-launch-surfaces" tabindex="-1">Two Launch Surfaces <a class="header-anchor" href="#two-launch-surfaces" aria-label="Permalink to &quot;Two Launch Surfaces&quot;">​</a></h2><p>It is critical to distinguish between the two distinct launchers used in this architecture. They are not the same, and updating one does not update the other:</p><ol><li><p><strong><code>access.qially.com</code> (The Public Portal)</strong></p><ul><li><strong>Role:</strong> External/public QiAccess landing page and primary user-facing front door when away from home/server.</li><li><strong>Tech:</strong> Static/React app deployed through Cloudflare.</li><li><strong>Config:</strong> Service links must be maintained directly in the app source data files. It does <em>not</em> read from the server&#39;s <code>services.yaml</code>.</li></ul></li><li><p><strong><code>qiserver-1.cerberus-sirius.ts.net</code> (The Private Server Utility)</strong></p><ul><li><strong>Role:</strong> Private Tailscale/server launcher, useful strictly for local/tailnet access.</li><li><strong>Tech:</strong> <code>gethomepage</code> local server utility.</li><li><strong>Config:</strong> Configuration lives at <code>/srv/qios/stacks/_qiaccess_start/config/services.yaml</code>. Editing this file updates the local utility, <em>not</em> the public landing page.</li></ul></li></ol><h2 id="portal-contract" tabindex="-1">Portal Contract <a class="header-anchor" href="#portal-contract" aria-label="Permalink to &quot;Portal Contract&quot;">​</a></h2><p>The portal has seven roots only:</p><ol><li><code>Home</code></li><li><code>Start</code></li><li><code>Capture</code></li><li><code>Knowledge</code></li><li><code>Memory</code></li><li><code>Insights</code></li><li><code>System</code></li></ol><h2 id="root-intent" tabindex="-1">Root Intent <a class="header-anchor" href="#root-intent" aria-label="Permalink to &quot;Root Intent&quot;">​</a></h2><ul><li><code>Home</code>: orient the day and show the next useful actions</li><li><code>Start</code>: open tools, services, projects, and working surfaces</li><li><code>Capture</code>: get notes, links, reminders, files, and observations out fast</li><li><code>Knowledge</code>: point to docs, runbooks, manuals, and references</li><li><code>Memory</code>: preserve continuity, decisions, and context once ingestion exists</li><li><code>Insights</code>: hold summaries, patterns, reports, and future analysis</li><li><code>System</code>: hold nested access, server, storage, governance, and diagnostics surfaces</li></ul><h2 id="routes" tabindex="-1">Routes <a class="header-anchor" href="#routes" aria-label="Permalink to &quot;Routes&quot;">​</a></h2><p>Use this route model:</p><ul><li><code>/</code> = Home</li><li><code>/start</code> = Start</li><li><code>/capture</code> = Capture</li><li><code>/quick</code> = mobile quick capture</li><li><code>/knowledge</code> = Knowledge</li><li><code>/memory</code> = Memory</li><li><code>/insights</code> = Insights</li><li><code>/system</code> = System</li></ul><p>System subroutes:</p><ul><li><code>/system/access</code></li><li><code>/system/server</code></li><li><code>/system/storage</code></li><li><code>/system/integrations</code></li><li><code>/system/settings</code></li><li><code>/system/blueprint</code></li><li><code>/system/roadmap</code></li><li><code>/system/security</code></li><li><code>/system/diagnostics</code></li></ul><h2 id="current-phase" tabindex="-1">Current Phase <a class="header-anchor" href="#current-phase" aria-label="Permalink to &quot;Current Phase&quot;">​</a></h2><p>The current phase is stabilization and prototype flow validation.</p><p>The shortest path to daily usefulness is:</p><ol><li>Start opens real tools</li><li>Capture reduces friction</li><li>Knowledge points to real docs</li><li>System keeps infrastructure honest and visible</li><li>Storage maps QiNexus targets</li><li>Memory and Insights stay clearly marked until they are real</li></ol><h2 id="design-rule" tabindex="-1">Design Rule <a class="header-anchor" href="#design-rule" aria-label="Permalink to &quot;Design Rule&quot;">​</a></h2><p>The portal should feel like a deliberate entry point into a real operating environment.</p><ul><li>modern</li><li>fast</li><li>low-friction</li><li>visually distinct by root</li><li>no dead controls</li><li>no fake intelligence claims</li></ul><h2 id="legacy-disposition" tabindex="-1">Legacy Disposition <a class="header-anchor" href="#legacy-disposition" aria-label="Permalink to &quot;Legacy Disposition&quot;">​</a></h2><p>The older QiPortals and multi-tenant client portal material is not active doctrine for this page.</p><p>Useful governance fragments may be retained, but legacy platform assumptions belong in:</p><ul><li><code>08_appendices/20_legacy/legacy_salvage.md</code></li><li><code>08_appendices/20_legacy/qiaccess_start_legacy_quarantine.md</code></li></ul><h2 id="daily-use-priority" tabindex="-1">Daily-use priority <a class="header-anchor" href="#daily-use-priority" aria-label="Permalink to &quot;Daily-use priority&quot;">​</a></h2><p>The shortest path to daily use is:</p><ol><li>Start opens tools</li><li>Capture reduces friction</li><li>Knowledge points to real docs</li><li>System keeps private infrastructure visible</li><li>Storage shows QiNexus targets</li><li>Memory and Insights remain honest placeholders</li><li>Paperless ingestion becomes the first proven intake pipeline</li></ol><h2 id="current-build-rule" tabindex="-1">Current Build Rule <a class="header-anchor" href="#current-build-rule" aria-label="Permalink to &quot;Current Build Rule&quot;">​</a></h2><p>Prototype inside the existing repo and preserve what already works.</p><ul><li>no repo split</li><li>no auth rebuild</li><li>no deployment churn before flow is validated</li><li>no fake intelligence claims</li><li>static or honest placeholder content is acceptable during stabilization</li></ul>',33)])])}const m=i(l,[["render",s]]);export{h as __pageData,m as default};
